import UIKit

class SceneDelegate: UIResponder, UIWindowSceneDelegate {

    var window: UIWindow?

    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = (scene as? UIWindowScene) else { return }

        window = UIWindow(windowScene: windowScene)
        let viewController = ViewController()
        window?.rootViewController = viewController
        window?.makeKeyAndVisible()

        // Handle Universal Link if the app was launched directly by it
        if let userActivity = connectionOptions.userActivities.first(where: { $0.activityType == NSUserActivityTypeBrowsingWeb }),
           let url = userActivity.webpageURL {
            handlePromoURL(url)
        }
    }

    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        // Handle Universal Link if the app was already running or in the background
        if userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handlePromoURL(url)
        }
    }

    private func handlePromoURL(_ url: URL) {
        // Validate the host and path to ensure it's our expected promo link
        guard url.host == "myapp.com", url.path == "/promo" else {
            print("Received URL does not match promo link pattern: \(url.absoluteString)")
            return
        }

        var promoCode: String?
        var discount: String?

        // Parse URL components to extract query parameters
        if let components = URLComponents(url: url, resolvingAgainstBaseURL: false) {
            for item in components.queryItems ?? [] {
                switch item.name {
                case "code":
                    promoCode = item.value
                case "discount":
                    discount = item.value
                default:
                    break // Ignore other parameters
                }
            }
        }

        // Update the UI with the extracted promo details
